INSERT INTO "public"."knowledge_points" VALUES (1, 'math', 'primary', 1, '一年级', 'up', '准备课', '数一数与比多少', 'formula', '1~10的顺序；同样多、多、少；一一对应。', '2026-04-07 14:30:54');
