INSERT INTO "public"."problems" VALUES (2, 8, 'Question_1779548452183', '小明骑自行车以每秒5米的速度匀速前进。突然，他看见前方20米处有一只小猫横穿马路，立即刹车。已知他的反应时间为0.6秒，刹车后 自行车以每秒减少2米的速度减速。 问： (1)从看见小猫到自行车完全停下，一共需要多少时间? (2)自行车是否会撞到小猫?', NULL, NULL, NULL, '小明骑自行车以每秒5米的速度匀速前进。突然，他看见前方20米处有一只小猫横穿马路，立即刹车。已知他的反应时间为0.6秒，刹车后自行车以每秒减少2米的速度减速。
问：
(1)从看见小猫到自行车完全停下，一共需要多少时间?
(2)自行车是否会撞到小猫?', '4eab3886877f922ec2696e482b70ad75', 'https://oss-pai-q69568m1rpn68fpbj7-cn-shanghai.oss-cn-shanghai.aliyuncs.com/question-2511/image_1779548448083_lvg3cexk7.jpeg', NULL, NULL, NULL, NULL, NULL, 'math', NULL, NULL, 'A', 1, NULL, NULL, 0.95, 'aliyun', NULL, 1, '2026-05-23 23:00:52.184864', '2026-05-23 23:00:52.184864', NULL, NULL, NULL, NULL);
